const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const BRIEF_DIR = path.join(PROJECT, '.claude');

// Ensure .claude directory exists
if (!fs.existsSync(BRIEF_DIR)) fs.mkdirSync(BRIEF_DIR, { recursive: true });

const output = $('Merge Brief').item.json.output || '';

// Try to parse as JSON, clean up if needed
let briefJson = output;
try {
  // Remove markdown fences if present
  briefJson = briefJson.replace(/^```json\n?/m, '').replace(/\n?```$/m, '').trim();
  // Validate it's valid JSON
  const parsed = JSON.parse(briefJson);
  briefJson = JSON.stringify(parsed, null, 2);
} catch (e) {
  // If not valid JSON, wrap in an object
  briefJson = JSON.stringify({ raw_output: output, parse_error: e.message }, null, 2);
}

// Write design-brief.json
const briefPath = path.join(BRIEF_DIR, 'design-brief.json');
fs.writeFileSync(briefPath, briefJson);

// Also collect intermediate outputs for reference
const allOutputs = {
  competitor_analysis: $('Competitor Analysis').item.json.output || '',
  ux_patterns: $('UX Patterns').item.json.output || '',
  ui_audit: $('UI Audit').item.json.output || '',
  design_brief: briefJson,
};

const fullPath = path.join(BRIEF_DIR, 'ui-research-full.json');
fs.writeFileSync(fullPath, JSON.stringify(allOutputs, null, 2));

return [{ json: { status: 'OK', brief_path: briefPath, full_path: fullPath, brief_preview: briefJson.substring(0, 500) + '...' } }];
